using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a JSON placeholder REST API.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The user ID (1-10)")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Optional user ID to filter posts by author")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool, Description("Create a new post with a title and body for a given user.")]
    public async Task<string> CreatePost(
        [Description("The author's user ID")] int userId,
        [Description("Title of the post")] string title,
        [Description("Body content of the post")] string body,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);
        var payload = new { userId, title, body };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }
}

